"use client";

import { useEffect, useMemo, useState } from "react";
import { useAccount, useBalance, useSendTransaction } from "wagmi";
import { parseEther } from "viem";
import { io } from "socket.io-client";
import { TOKENS } from "@/lib/tokens";

/* ================= SOCKET ================= */
const socket = io("https://iopndex.onrender.com", {
  transports: ["websocket"],
  });

  /* ================= FORMAT ================= */
  function formatBalance(value: any) {
    if (!value) return "0.00";
      return Number(value.formatted || 0).toFixed(2);
      }

      /* ================= PAGE ================= */
      export default function PayPage() {
        const { address, isConnected } = useAccount();

          const [recipient, setRecipient] = useState("");
            const [amount, setAmount] = useState("");
              const [tokenSymbol, setTokenSymbol] = useState("OPN");
                const [txHash, setTxHash] = useState<string | null>(null);
                  const [liveTxs, setLiveTxs] = useState<any[]>([]);

                    const token = useMemo(
                        () => TOKENS.find((t) => t.symbol === tokenSymbol),
                            [tokenSymbol]
                              );

                                const { data: balance } = useBalance({ address });

                                  const { sendTransactionAsync } = useSendTransaction();

                                    /* ================= SEND TX ================= */
                                      async function sendTx() {
                                          if (!isConnected || !address) {
                                                alert("Connect wallet first");
                                                      return;
                                                          }

                                                              if (!recipient || !amount) {
                                                                    alert("Missing fields");
                                                                          return;
                                                                              }

                                                                                  try {
                                                                                        const tx = await sendTransactionAsync({
                                                                                                to: recipient as `0x${string}`,
                                                                                                        value: parseEther(amount),
                                                                                                              });

                                                                                                                    setTxHash(tx);

                                                                                                                          await fetch("https://iopndex.onrender.com/api/send", {
                                                                                                                                  method: "POST",
                                                                                                                                          headers: { "Content-Type": "application/json" },
                                                                                                                                                  body: JSON.stringify({
                                                                                                                                                            from: address,
                                                                                                                                                                      to: recipient,
                                                                                                                                                                                amount,
                                                                                                                                                                                          token: tokenSymbol,
                                                                                                                                                                                                    hash: tx,
                                                                                                                                                                                                              chainId: 984,
                                                                                                                                                                                                                      }),
                                                                                                                                                                                                                            });

                                                                                                                                                                                                                                  setRecipient("");
                                                                                                                                                                                                                                        setAmount("");

                                                                                                                                                                                                                                              alert("Transaction sent 🚀");
                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                        console.error(err);
                                                                                                                                                                                                                                                              alert("Transaction failed ❌");
                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                      /* ================= SOCKET ================= */
                                                                                                                                                                                                                                                                        useEffect(() => {
                                                                                                                                                                                                                                                                            socket.on("connect", () => {
                                                                                                                                                                                                                                                                                  console.log("Socket connected:", socket.id);
                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                          socket.on("newTx", (tx) => {
                                                                                                                                                                                                                                                                                                setLiveTxs((prev) => [tx, ...prev]);
                                                                                                                                                                                                                                                                                                    });

                                                                                                                                                                                                                                                                                                        socket.on("txConfirmed", (data) => {
                                                                                                                                                                                                                                                                                                              setLiveTxs((prev) =>
                                                                                                                                                                                                                                                                                                                      prev.map((tx) =>
                                                                                                                                                                                                                                                                                                                                tx.hash === data.hash ? { ...tx, status: "confirmed" } : tx
                                                                                                                                                                                                                                                                                                                                        )
                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                      return () => {
                                                                                                                                                                                                                                                                                                                                                            socket.off("connect");
                                                                                                                                                                                                                                                                                                                                                                  socket.off("newTx");
                                                                                                                                                                                                                                                                                                                                                                        socket.off("txConfirmed");
                                                                                                                                                                                                                                                                                                                                                                            };
                                                                                                                                                                                                                                                                                                                                                                              }, []);

                                                                                                                                                                                                                                                                                                                                                                                return (
                                                                                                                                                                                                                                                                                                                                                                                    <div className="min-h-screen bg-black text-white p-6">

                                                                                                                                                                                                                                                                                                                                                                                          {/* HEADER */}
                                                                                                                                                                                                                                                                                                                                                                                                <div className="mb-6">
                                                                                                                                                                                                                                                                                                                                                                                                        <h1 className="text-2xl font-bold">IOPN Pay</h1>

                                                                                                                                                                                                                                                                                                                                                                                                                <p className="text-white/60">
                                                                                                                                                                                                                                                                                                                                                                                                                          Balance: {formatBalance(balance)} {tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                  </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                          {txHash && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-green-400 text-xs mt-2 break-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                Last Tx: {txHash}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* TOKEN SELECTOR */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <select
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={tokenSymbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onChange={(e) => setTokenSymbol(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {TOKENS.map((t) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <option key={t.symbol} value={t.symbol}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {t.symbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </select>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {/* FORM */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="space-y-4">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  placeholder="Recipient address"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            value={recipient}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onChange={(e) => setRecipient(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="w-full p-3 bg-white/10 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          placeholder="Amount"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    value={amount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onChange={(e) => setAmount(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        onClick={sendTx}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="w-full p-3 bg-green-500 text-black font-bold rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Send Transaction
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* FEATURE BUTTONS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex gap-3 mt-4 relative z-10">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onClick={() => alert("Receive: show QR / address")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="flex-1 bg-white/10 p-3 rounded-xl"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Receive
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClick={() => alert("Virtual Card coming soon")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="flex-1 bg-white/10 p-3 rounded-xl"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Virtual Card
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* LIVE TX */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="mt-10">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <h2 className="text-lg font-bold mb-3">Live Transactions</h2>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {liveTxs.length === 0 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-white/40">No transactions yet</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {liveTxs.map((tx, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div key={i} className="p-3 border-b border-white/10">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="text-sm text-white/60">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {tx.from} → {tx.to}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-green-400">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {tx.amount} {tx.token}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </p>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="text-xs text-white/40">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      Status: {tx.status || "pending"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }